var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"꺄아악!","JPN":"きゃああっ！","ENG":"Kyaaaah!","TWN":"啊啊啊！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"들립니다! 아이들 목소리입니다!","JPN":"聞こえます！　子供たちの声です！","ENG":"I hear them! It's the children!","TWN":"是孩子們的聲音！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"나도 들었다. 폐허 쪽 건물에 숨어 있는 건가?","JPN":"俺も聞いたぞ。廃墟の方にある建物に隠れてんのか？","ENG":"I heard them too! Are they hiding somewhere inside the ruins?","TWN":"我也有聽到，是躲在廢墟那的建築物裡嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"하지만 너무 멀어. 무슨 일이 생기기 전에 도착할 수 있을지…","JPN":"だが遠すぎるな。何かが起こる前に到着できるかどうか……","ENG":"It's too far. I'm not sure if we'll be able to reach them in time...","TWN":"但太遠，不知道在途中會不會發生什麼事…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"뒤따라오도록. 내가 먼저 가겠다.","JPN":"ついて来い。私が先に行こう。","ENG":"Follow me. I'll take the lead.","TWN":"我先出發，你們隨後跟上。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"뭐? 이봐, 뭘 멋대로……!","JPN":"は？　おい、何を勝手に……！","ENG":"Huh?! Hey! You can’t–!","TWN":"什麼？喂，你別胡來……！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"기다려! 혼자 뛰어드는 건 위험해!","JPN":"待て！　一人で飛び込むと危ねえぞ！","ENG":"Wait! It's dangerous to go alone!","TWN":"等等！一個人衝進去會很危險！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"망할! 무슨 말이 저렇게 빨라?!","JPN":"くそ！　なんて早い馬なんだ！？","ENG":"Dammit! That horse is wicked fast!","TWN":"該死！那隻馬還跑真快？！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"괜찮지 않을까요? 저 자가 정말로 그 총사대의 큐리안이라면……","JPN":"大丈夫じゃないでしょうか？　あの者が本当にあの銃士隊のキュリアンなら……","ENG":"Won't he be okay? I mean, if he really is the Curian we think he is...","TWN":"沒問題吧？那個人如果真的是射擊隊的庫里安……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"큐리안이 아니면?! 사람 목숨으로 도박할 셈이냐!","JPN":"キュリアンじゃなかったらどうすんだ！？　人の命でギャンブルでもするつもりか！","ENG":"And what if he's not?! Are you going to gamble with another person's life?!","TWN":"萬一不是呢？！你這是在拿人命開玩笑嗎！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"멍청한 소리 하지 말고 쫓아!","JPN":"バカなこと言わないで追え！","ENG":"Don't be stupid, chase after him!","TWN":"廢話少說，追！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"네, 넵!","JPN":"は、はい！","ENG":"Y-yes, sir!","TWN":"是，遵命！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L19_1","type":"dialog","speaker":"NOMAD_BORDER_A_KID","text":{"KOREA":"안 돼. 저러다 문이 부서지겠어.","JPN":"まずい、あのままじゃ扉が壊れちゃう。","ENG":"No... They're gonna break the door.","TWN":"糟糕，這樣下去門會被撞碎啦！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_ROCK_SMALL_02"},{"id":"L20_1","type":"dialog","speaker":"NOMAD_BORDER_B_KID","text":{"KOREA":"씨이… 그러길래 내가 얼른 가자고 했잖아.","JPN":"うう……だから早く行こうって言ったのに。","ENG":"Grr... See? I told you we had to get out of here fast!","TWN":"可惡…所以我才說要趕離開的嘛！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NOMAD_BORDER_A_KID","text":{"KOREA":"너도 좋대매! 지난번엔 여기까진 안전했었다고 했으면서!","JPN":"お前も賛成したろ！　この前はここまで安全だったって言ったくせに！","ENG":"You said it was okay! You're the one who said it was safe here last time!","TWN":"你剛才自己也說好的！還說什麼上次來也沒事！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"NOMAD_BORDER_C_KID","text":{"KOREA":"잠깐만, 얘들아. 소리가 안 들려.","JPN":"ちょっと、みんな。音が聞こえないよ。","ENG":"Guys, wait. I can't hear anything.","TWN":"你們先別吵，沒聲音咧？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"NOMAD_BORDER_A_KID","text":{"KOREA":"어? 그냥 포기하고 갔나?","JPN":"あれ？　諦めて行ったのかな？","ENG":"Huh? Did they give up and leave?","TWN":"嗯？它放棄了嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"NOMAD_BORDER_B_KID","text":{"KOREA":"꺄악! 벽이 무너졌어!","JPN":"きゃっ！　壁が崩れた！","ENG":"Kyaak! They broke the wall!","TWN":"哇啊！牆倒了！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"NOMAD_BORDER_C_KID","text":{"KOREA":"다들 도망쳐!","JPN":"みんな逃げて！","ENG":"RUN!!","TWN":"大家快逃！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"NOMAD_BORDER_A_KID","text":{"KOREA":"아, 안 돼! 문을 막아 놔서 나갈 데가 없어!","JPN":"だ、ダメだよ！　扉が塞がれてて出られない！","ENG":"W-we can't! They're blocking the way out!","TWN":"唔，糟糕！門堵住出不去！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CORRUPTED_NPC_MONTSER_B","text":{"KOREA":"크르륵……!","JPN":"グルル……！","ENG":"Grrrrr!","TWN":"咯咯……！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_19"},{"id":"L37_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"네 상대는 이쪽이다.","JPN":"お前の相手はこちらだ。","ENG":"Your opponent is me.","TWN":"你的對手在這邊。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"NOMAD_BORDER_A_KID","text":{"KOREA":"저 사람… 말 되게 잘 탄다…","JPN":"あの人……すげえ……","ENG":"That person... He's a really good rider...","TWN":"那個人…好會騎馬…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"NOMAD_BORDER_B_KID","text":{"KOREA":"대장님이 구했던 그 아저씨야! 멋지다!","JPN":"隊長が助けたあのおじさんだよ！　カッコいい！","ENG":"It's the guy Captain saved! Cool!","TWN":"是隊長救的那個大叔！好帥！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"NOMAD_BORDER_C_KID","text":{"KOREA":"뭐 해! 저 괴물이 없을 때 얼른 빠져나가자!","JPN":"何してるの！　あの化け物がいないうちに早く出よう！","ENG":"What are you doing?! We need to get out of here while the monster's not looking at us!","TWN":"你們在幹什麼！趁那個怪物不在的時候，趕緊逃出去吧！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"NOMAD_BORDER_B_KID","text":{"KOREA":"으, 응!","JPN":"う、うん！","ENG":"O-okay!","TWN":"喔，嗯！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"NOMAD_BORDER_B_KID","text":{"KOREA":"꺄악!","JPN":"きゃっ！","ENG":"Kyaah!","TWN":"哇啊！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"NOMAD_BORDER_A_KID","text":{"KOREA":"다들 뛰어! 한 마리 더 있었어!!","JPN":"みんな走れ！　もう一匹いた！！","ENG":"RUN! There's another one!!","TWN":"大家快逃！還有一隻！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"NOMAD_BORDER_C_KID","text":{"KOREA":"어떡해! 루시가 넘어졌어!","JPN":"どうしよう！　ルーシーが転んじゃったよ！","ENG":"No!! Lucy fell!","TWN":"怎麼辦！露西跌倒了！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"이런, 한 마리 더 있었나?","JPN":"おっと、もう一匹いたのか？","ENG":"Gah, there's another one?","TWN":"糟糕，還有一隻嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"여기다! 이 괴물아!","JPN":"こっちだ！　化け物！","ENG":"Hey monster! Over here!","TWN":"臭怪物！看這裡！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"약오르냐? 약오르지? 그럼 어디 쫓아와 보시지!","JPN":"ムカつくか？　ムカつくだろ？　じゃあ、ついて来いよ！","ENG":"You wanna piece of me? Don't ya? Then let's see if you can catch me!","TWN":"你很不爽嗎？很不爽對吧？來追我啊！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"저 소년은…?","JPN":"あの少年は……？","ENG":"Isn't that...?","TWN":"那少輕人是…？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NOMAD_BORDER_C_KID","text":{"KOREA":"피터잖아! 저 바이크 언제 고쳤지?!","JPN":"ピーターだ！　あのバイク、いつ直したんだろう！？","ENG":"It's Peter! When did he fix his bike?!","TWN":"是彼得！那台車是什麼時候修好的？！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NOMAD_BORDER_A_KID","text":{"KOREA":"지금이야, 루시! 얼른 일어나!","JPN":"今だ、ルーシー！　早く立て！","ENG":"Now, Lucy! Get up and run!","TWN":"趁現在，露西！快站起來！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"갑피가 계속 재생되는군. 이대로는 이쪽의 총탄이 먼저 바닥나겠어.","JPN":"甲殻はいくらでも再生するのか。このままではこちらの銃弾が先に尽きそうだな。","ENG":"So its armor regenerates... It'll only be a matter of time before I run out of bullets.","TWN":"原本打中的地方一直在癒合，再這樣下去，恐怕我的子彈會先用光。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L21_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그 여자가 말한 관절부…… 움직일 때 드러나는 저 붉은 부분인가?","JPN":"あの女が言ってた関節部……動く時に見えるあの赤い部分なのか？","ENG":"The joints that she was talking about... Are they those red spots that appear when it moves?","TWN":"她說的關節……是指移動時露出的紅色部分嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"지금이다!","JPN":"今だ！","ENG":"Now!","TWN":"就是現在！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"해치웠군. ……음?","JPN":"やっつけたな。……うん？","ENG":"Did it work? ...Hmm?","TWN":"解決掉了……嗯？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"우와아앗! 따라잡힌다아아!","JPN":"うわああっ！　追いつかれるうう！","ENG":"WHOAA!! It's gaining up on me!","TWN":"哇啊啊啊！快追上來啦！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"괜찮나, 소년?","JPN":"大丈夫か？　少年。","ENG":"Boy, you all right?","TWN":"年輕人，你沒事吧？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"우와…… 저 괴물을 단 한 발로 해치운 거예요?","JPN":"うわ……あの化け物を一発でやっつけたんですか？","ENG":"Whoa... Did you just kill it with one shot?","TWN":"哇賽…一槍就處理掉那個怪物喔？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"다리의 관절을 맞춘 것뿐이다. 내버려 두면 다시 일어나서 덤벼들겠지.","JPN":"足の関節に当てただけだ。放っておいたらまた起き上がって飛びかかって来るだろう。","ENG":"I just hit one of its joints. It'll get back up and charge at us if we don't do anything about it.","TWN":"我只是打中它腿部的關節，不理它的話，它還會再爬起來的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"그, 그럼 어서 해치워 버려야죠!","JPN":"じゃ、じゃあ早くやっつけないと！","ENG":"Th-then go kill it now!","TWN":"那…那趕快解決它吧！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그건 안 되겠어. 탄환이 다 떨어졌다.","JPN":"それは無理だな。弾丸が切れた。","ENG":"I can't. I'm all out of bullets.","TWN":"沒辦法，沒子彈了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"네에에에?! 그럼 왜 말에서 내리는 거예요! 얼른 도망쳐야죠!","JPN":"ええええっ！？　じゃあなんで馬から降りるんですか！　早く逃げましょうよ！","ENG":"WHAAAT?! Then why are you getting off your horse?! We gotta go!","TWN":"什麼？？那你下馬幹嘛！還不快逃！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"걱정 마라. 탄환이 없다고 싸우지 못하는 건 아니니까.","JPN":"心配するな。弾丸がなくては戦えないというわけじゃない。","ENG":"Don't worry about me. Just because I'm out of bullets doesn't mean I can't fight.","TWN":"放心，誰說一定要有子彈才能打。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"하아아앗!","JPN":"はあああっ！","ENG":"Haaaaa!!!!","TWN":"嚇啊啊啊！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그래서 다짜고짜 말에서 내려 침식체에게 주먹질을 했다고?","JPN":"それで、いきなり馬から降りて侵食体を殴ったって？","ENG":"So you just got off your horse and punched the C.O.?","TWN":"所以你就二話不說下馬，然後赤手空拳對付侵蝕體？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그래.","JPN":"ああ。","ENG":"Yes.","TWN":"沒錯。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그걸 맞은 침식체는 꿈쩍도 하지 않았고?","JPN":"拳をくらった侵食体はビクともしなかったって？","ENG":"And the C.O. got no damage?","TWN":"挨打的侵蝕體都沒反應嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"발을 삐끗해서 힘이 제대로 안 들어간 모양이야.","JPN":"つまずいてちゃんと力が入らなかったようだ。","ENG":"I sprained my ankle, so I wasn't able to hit it with all of my strength.","TWN":"因為腳扭到，使不上力的樣子。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"무모하네. 카운터라도 침식체와 맨몸으로 싸우는 경우는 드물어.","JPN":"無茶ね。カウンターであってもそうそう侵食体と素手で戦ったりしない。","ENG":"Reckless. It's rare to see someone fight a C.O. with their bare hands, even for a Counter.","TWN":"真是魯莽，就算是制裁者，也幾乎沒有人會赤手空拳對付侵蝕體的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"이번에 실감했다. 부끄럽군.","JPN":"今回実感した。恥ずかしいな。","ENG":"Yeah, didn't take me too long to find that out for myself.","TWN":"這次真的是親身體驗到，真是慚愧。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"뒤늦게 도착한 대원들 말로는 침식체가 휘두르는 팔에 맞고 쐐기창처럼 날아갔다던데.","JPN":"遅れて到着した隊員たちの話では、侵食体が振り回した腕に当たってくさび槍のように飛んでいったそうだね。","ENG":"I heard from the others who arrived later that you were hit by its swinging arms and went flying like a Ironshot Spear.","TWN":"根據後來抵達的隊員說法，你被侵蝕體揮舞的手臂打到，像子彈一樣飛出去。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"굳이 과장되게 묘사를 하자면 그렇게 되겠지.","JPN":"しいて大げさに描写するならそうなるだろうな。","ENG":"That's a bit of an exaggeration, but yeah.","TWN":"誇飾法的話，差不多是那樣。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"……후우. 좋아.","JPN":"……ふう。よし。","ENG":"Oh dear... Okay.","TWN":"……哀，好吧。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"일어나. 막지 않을 테니까 어디 날 한 번 주먹으로 있는 힘껏 쳐 봐.","JPN":"立って。防御はしないから、私をげんこつで力いっぱい殴ってみて。","ENG":"Get up. Hit me with all you've got. I won't block it.","TWN":"你起來，我不會閃，你用力打我一拳。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"내가 전력을 다하면 뼈가 으스러질 텐데, 괜찮겠나?","JPN":"全力で殴ったら骨が砕けると思うんだが、大丈夫なのか？","ENG":"You sure? I might break your bones.","TWN":"用力的話，我怕你的骨頭會碎掉，這樣沒關係嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"먼저 안 치면 내가 칠 거야.","JPN":"先にやらないのなら私がやる。","ENG":"I’ll hit you first if you don’t.","TWN":"你不出拳的話，我就要出手囉。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"어쩔 수 없군. 그럼 실례하지.","JPN":"仕方ないな。それでは失礼しよう。","ENG":"Guess I don’t have a choice then.","TWN":"沒辦法，那就失禮了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"어때?","JPN":"どう？","ENG":"How does that feel?","TWN":"怎麼樣？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"부드러우면서도 단단하군. 오히려 내 손이 아플 지경이다.","JPN":"柔らかいながらも固いな。むしろ私の手が痛いほどだ。","ENG":"Soft, yet firm. But I think my hand is hurting even more.","TWN":"又軟又硬，反而是我的手很痛。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"혹시 자네의 카운터 능력은 방어에 특화되어 있는 건가?","JPN":"もしかして君のカウンターの能力は防御に特化しているのか？","ENG":"Is your Counter ability specialized in defense?","TWN":"難道你的制裁者能力在防禦方面特別強嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"난 아무짓 안 했어. 당신 주먹이 솜방망이인 거지.","JPN":"私は何もしていない。あなたの拳が弱すぎるだけ。","ENG":"I didn't do anything. It just mean you have a weak punch.","TWN":"我什麼都沒做，單純是你的拳頭太弱而已。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그리고 큐리안 같은 고등급 카운터라면 수술 상처쯤은 진작에 아물었어야 해.","JPN":"それに、キュリアンのような高ランクカウンターなら手術の傷などとっくに治ってるはずなんだ。","ENG":"Also, if you really are a high-grade Counter like Curian, your wounds should've fully healed by now.","TWN":"而且像庫里安這種高階制裁者，手術傷口應該早就要癒合才對。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"하지만 당신은 아물긴커녕 무리하게 움직이느라 상처가 벌어졌지. 있을 수 없는 일이야.","JPN":"でもあなたは治るどころか、無理に動いて傷口が開いてしまったし。あり得ないことだね。","ENG":"But they haven't, and you've ripped them even more by moving too much. It doesn't make any sense.","TWN":"可是你非但沒有癒合，還因爲過度活動，導致傷口裂開。這是不可能的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"이런 경우를 전에도 본 적이 있나?","JPN":"こういったケースを見たことは？","ENG":"Have you witnessed a similar case before?","TWN":"這種情況你以前見過嗎?"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"없어. 한 번도.","JPN":"ない。一度も。","ENG":"No. Not even once.","TWN":"沒有，一次也沒有。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"애초에 그림자가 되었어야 할 사람이 멀쩡히 살아 있는 것도 전례가 없고 말이야.","JPN":"だいたいシャドウになるはずだった人間が元気に生きてるというのも前例がないしね。","ENG":"But then again, you should've turned into a Shadow by now, but you haven't.","TWN":"原本應該變成暗影的人卻還活著，這也是史無前例。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그림자? 그게 뭐지?","JPN":"シャドウ？　何だそれは？","ENG":"\\"Shadow\\"? What's that?","TWN":"暗影？那是什麼？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"침식의 영향으로 침식체가 된 카운터. 정식 명칭은 데몬 타입이라고 불러.","JPN":"侵食の影響で侵食体になったカウンター。正式名称はデーモンタイプ。","ENG":"A Counter affected by the Corruption who turned into a C.O. They’re officially called Demon-Types.","TWN":"受侵蝕影響而成爲侵蝕體的制裁者，正式名稱是惡魔型。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"성자가 평범한 인간들처럼 침식의 영향을 받는다고? 처음 듣는 얘기군.","JPN":"聖者が普通の人間のように侵食に影響されるだと？　初めて聞くな。","ENG":"Helgons can get affected by Corruption just like normal people? This is the first time I’ve heard that.","TWN":"聖者像普通人一樣受到侵蝕的影響嗎？這我還是頭一次聽說呢。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"과거엔 모두 무지했으니까. 그래서 국경 저편엔 한때 카운터였던 그림자들이 많다고 해.","JPN":"昔はみんな無知だったからね。それで国境の向こうにはかつてカウンターだったシャドウが多いらしい。","ENG":"Because they didn't know about it in the past. That's why there are so many Shadows beyond the border.","TWN":"因爲過去大家都很無知，因此據說境那邊有很多曾經是制裁者的暗影。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"하지만 당신이 정말 20년간 국경 저편을 떠돌았다면, 관리국이 제시한 정보 대신 다른 가능성도 생각해 볼 수 있어.","JPN":"でもあなたが本当に20年間国境の向こうを彷徨ったのなら、管理局から提示された情報とは別の可能性も考えられるね。","ENG":"But seeing as you've been wandering out there for the past 20 years, there’s another possibility I can think of that is different from the Administration’s information.","TWN":"但若你真的在國境那邊滯留20年，那是可以不參考管理局提供的資訊，而是考量其他可能性。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"CRF를 완전히 소진한다고 반드시 그림자가 되는 게 아니라, 능력만 잃는다는 가능성 말이지.","JPN":"CRFを完全に消費しても必ずシャドウになるわけじゃなくて、能力だけを失うという可能性をね。","ENG":"Meaning that there's a possibility that Counters don’t become Shadows once they've completely exhausted their CRF, and simply lose their abilities.","TWN":"也就是說，CRF完全耗盡，並不一定會成爲暗影，可能只會失去能力。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"물론 그 첫 사례는 당신이 되는 거고.","JPN":"もちろんあなたが最初のケースになるけど。","ENG":"However, the first ever occurrence would be you, of course.","TWN":"當然，你就是第一個案例。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"관리국? 그건 재건단에 속한 기구 이름인가?","JPN":"管理局？　それは再建団所属の機構なのか？","ENG":"The Administration? Is that another organization within the Alliance?","TWN":"管理局？那是隸屬於重建委員會的機構名稱嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"전혀 달라. 어느 국가에도 속하지 않고, 침식의 날 이전부터 그 위협을 연구해 온 기관이야.","JPN":"全然違う。どの国家にも所属せず、侵食の日の以前からその脅威を研究してきた機関よ。","ENG":"No. The Administration is not a part of any country. It’s a research institute that has studied the threat of Corruption since before the Day of Corruption.","TWN":"完全不一樣，它不屬於任何國家，而且從侵蝕之日之前，就已經開始研究其威脅性的組織。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"침식의 날 이전부터? 바깥 세상에도 정착자 같은 사람들이 있었던 건가?","JPN":"侵食の日の以前から？　外の世界にも定着者のような者たちがいたのか？","ENG":"Before the Day of Corruption? You mean that there are others similar to the Settlers out there in the world?","TWN":"從侵蝕日之前嗎？難道外面的世界也有像定居者一樣的人嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"글쎄. 하지만 어느 쪽이나 그들의 도움이 아니었다면 우리가 생존하는 것도 힘들었겠지.","JPN":"どうかな。でもどちらにせよ、彼らの助けがなかったら私たちは生き残ることも難しかっただろうね。","ENG":"Who knows. But whatever the case may be, our chances of survival would've been slim without their help.","TWN":"不清楚，但若沒有他們的幫助，我們也很難生存下去。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"아, 그리고 아직 가장 중요한 얘기가 남았어.","JPN":"あ、それにまだ一番重要な話が残っている。","ENG":"Oh, I forgot to mention the most important thing.","TWN":"對了，還有一件最重要的事。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그게 뭐지?","JPN":"何だ？","ENG":"What's that?","TWN":"是什麼事？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"당신이 타고 다니던 그 병기마에 대해서야.","JPN":"あなたが乗っていたあの兵器馬のことよ。","ENG":"About your Armored Horse.","TWN":"就是關於你騎的那匹戰馬。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};